function showToast(message){let toast=document.getElementById('toast');if(!toast){toast=document.createElement('div');toast.id='toast';toast.className='toast';document.body.appendChild(toast);}
toast.textContent=message||'已复制到剪贴板 📋';toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2000);}
function copyQuote(element){const cn=element.querySelector('.quote-cn')?.textContent||'';const en=element.querySelector('.quote-en')?.textContent||'';const author=element.querySelector('.quote-author')?.textContent||'';const text=`${cn}\n${en}\n${author}`;navigator.clipboard.writeText(text).then(()=>{showToast('已复制到剪贴板 📋');}).catch(()=>{const ta=document.createElement('textarea');ta.value=text;document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);showToast('已复制到剪贴板 📋');});}
function refreshRandom(){const section=document.getElementById('random-section');const card=section.querySelector('.quote-card');card.style.opacity='0';card.style.transform='translateY(10px)';fetch('/api/random').then(res=>res.json()).then(data=>{card.querySelector('.quote-cn').textContent=data.cn;card.querySelector('.quote-en').textContent=data.en;card.querySelector('.quote-author').textContent='—— '+data.author;card.querySelector('.quote-category').textContent=data.category;card.style.transition='all 0.3s ease';card.style.opacity='1';card.style.transform='translateY(0)';}).catch(()=>{card.style.opacity='1';card.style.transform='translateY(0)';});}
function refreshJoke(){const section=document.getElementById('joke-section');const card=section.querySelector('.joke-card');card.style.opacity='0';card.style.transform='translateY(10px)';fetch('/api/joke/random').then(res=>res.json()).then(data=>{setupEl=card.querySelector('.joke-setup');if(data.joke_cn.includes('\n')){setupEl.innerHTML='<span class="joke-bubble">'+data.joke_cn.replace(/\n/g,'<br>')+'</span>';}else{setupEl.innerHTML='<span class="joke-bubble">'+data.joke_cn+'</span>';}
card.querySelector('.punchline-text').textContent=data.punchline_cn;card.querySelector('.joke-punchline').classList.add('hidden');const enEls=card.querySelectorAll('.joke-en');if(data.joke_en){if(enEls[0]){enEls[0].innerHTML='<span class="joke-en-label">EN:</span> '+data.joke_en;enEls[0].style.display='';}}else if(enEls[0]){enEls[0].style.display='none';}
const punchEnEls=card.querySelectorAll('.punchline-en');if(data.punchline_en&&punchEnEls.length>0){punchEnEls[0].innerHTML='<span class="joke-en-label">→</span> '+data.punchline_en;punchEnEls[0].style.display='';punchEnEls[0].classList.add('hidden');}else if(punchEnEls.length>0){punchEnEls[0].style.display='none';}
card.querySelector('.joke-category').textContent=data.category;card.style.transition='all 0.3s ease';card.style.opacity='1';card.style.transform='translateY(0)';}).catch(()=>{card.style.opacity='1';card.style.transform='translateY(0)';});}
document.addEventListener('DOMContentLoaded',function(){const countSpans=document.querySelectorAll('[id^="count-"]');if(countSpans.length>0){fetch('/api/categories').then(res=>res.json()).then(data=>{const categories=Object.keys(data.counts);countSpans.forEach((span,i)=>{if(i<categories.length){span.textContent=data.counts[categories[i]]+' 条';}});}).catch(()=>{countSpans.forEach(span=>span.textContent='');});}
document.querySelectorAll('.quote-card:not([onclick])').forEach(card=>{card.addEventListener('click',()=>copyQuote(card));card.title='点击复制';});});